import multer, { MulterError } from 'multer';
import { Request, Response, NextFunction } from 'express';
import { logger } from '../logger';

const MAX_FILE_SIZE = 50 * 1024 * 1024; // 50MB

const storage = multer.diskStorage({
  destination: '/data/uploads/tmp/',
  filename: (req, file, cb) => {
    const chunkId = req.headers['x-chunk-id'] || crypto.randomUUID();
    cb(null, `chunk_${chunkId}_${Date.now()}.part`);
  },
});

const upload = multer({ storage, limits: { fileSize: MAX_FILE_SIZE } });

export function uploadHandler() {
  return (req: Request, res: Response, next: NextFunction) => {
    upload.single('file')(req, res, (err) => {
      if (err) {
        if (err instanceof MulterError) {
          if (err.code === 'LIMIT_FILE_SIZE') {
            return res.status(413).json({ error: 'File too large', maxSize: '50MB' });
          }
          return res.status(400).json({ error: err.message });
        }
        // BUG: System errors like ENOSPC fall through to generic 500
        logger.error('Upload error:', err);
        return res.status(500).json({ error: 'Internal server error' });
      }
      next();
    });
  };
}

