import { open, readdir, stat, unlink } from 'fs/promises';
import { join } from 'path';
import { logger } from './logger';

interface CleanupConfig {
  maxAgeHours: number;
  targetDir: string;
  batchSize: number;
  dryRun: boolean;
  skipPattern?: string;
}

const LOCK_PATH = '/var/run/upload-svc/cleanup.lock';

export async function runCleanup(config: CleanupConfig): Promise<void> {
  // Open the lock file and acquire an exclusive advisory lock via flock().
  // The OS releases this automatically if the process exits, crashes, or is
  // killed — no stale lock files possible.
  const lockFd = await open(LOCK_PATH, 'w');
  try {
    await lockFd.flock('ex');  // non-blocking exclusive lock
    logger.info('Lock acquired successfully');
  } catch (err) {
    await lockFd.close();
    logger.error(`Failed to acquire lock: ${LOCK_PATH} — ${(err as Error).message}`);
    logger.error('Another cleanup process may be running. Aborting.');
    return;
  }

  try {
    const cutoff = Date.now() - config.maxAgeHours * 3600_000;
    const files = await readdir(config.targetDir);
    const staleFiles: string[] = [];

    for (const file of files) {
      if (config.skipPattern && file.includes(config.skipPattern.replace('*', ''))) continue;
      const filePath = join(config.targetDir, file);
      const stats = await stat(filePath);
      if (stats.mtimeMs < cutoff) staleFiles.push(filePath);
    }

    logger.info(`Found ${staleFiles.length} files to delete`);

    let deletedCount = 0;
    for (let i = 0; i < staleFiles.length; i += config.batchSize) {
      const batch = staleFiles.slice(i, i + config.batchSize);
      const batchNum = Math.floor(i / config.batchSize) + 1;
      const totalBatches = Math.ceil(staleFiles.length / config.batchSize);
      logger.info(`Batch ${batchNum}/${totalBatches}: deleting ${batch.length} files...`);

      if (!config.dryRun) {
        await Promise.all(batch.map(f => unlink(f)));
        deletedCount += batch.length;
      }
    }

    logger.info(`Cleanup complete: deleted ${deletedCount} files`);
  } finally {
    // Releasing the lock: closing the fd releases the flock() automatically.
    await lockFd.close();
    logger.info('Lock released');
  }
}

