import { openSync, closeSync, constants } from 'fs';
import { readdir, stat, unlink } from 'fs/promises';
import { join } from 'path';
import { logger } from './logger';

// Use flock-style advisory locking via a file descriptor. The OS automatically
// releases the lock when the process exits for any reason (including SIGKILL),
// eliminating the stale lock problem from proper-lockfile's PID-based approach.
import { dlopen, ptr, suffix } from 'bun:ffi';

const LOCK_EX = 2; // exclusive lock
const LOCK_NB = 4; // non-blocking
const LOCK_UN = 8; // unlock

const libc = dlopen(`libc.${suffix}`, {
  flock: { args: ['i32', 'i32'], returns: 'i32' },
});

interface CleanupConfig {
  maxAgeHours: number;
  targetDir: string;
  batchSize: number;
  dryRun: boolean;
  skipPattern?: string;
}

export async function runCleanup(config: CleanupConfig): Promise<void> {
  const lockPath = '/var/run/upload-svc/cleanup.lock';

  const lockFd = openSync(lockPath, constants.O_CREAT | constants.O_WRONLY);
  const acquired = libc.symbols.flock(lockFd, LOCK_EX | LOCK_NB) === 0;

  if (!acquired) {
    closeSync(lockFd);
    logger.error(`Failed to acquire lock: ${lockPath} — another cleanup process is running. Aborting.`);
    return;
  }

  logger.info('Lock acquired successfully');

  try {
    const cutoff = Date.now() - config.maxAgeHours * 3600_000;
    const files = await readdir(config.targetDir);
    const staleFiles = [];

    for (const file of files) {
      if (config.skipPattern && file.includes(config.skipPattern.replace('*', ''))) continue;
      const filePath = join(config.targetDir, file);
      const stats = await stat(filePath);
      if (stats.mtimeMs < cutoff) staleFiles.push(filePath);
    }

    logger.info(`Found ${staleFiles.length} files to delete`);

    for (let i = 0; i < staleFiles.length; i += config.batchSize) {
      const batch = staleFiles.slice(i, i + config.batchSize);
      const batchNum = Math.floor(i / config.batchSize) + 1;
      const totalBatches = Math.ceil(staleFiles.length / config.batchSize);
      logger.info(`Batch ${batchNum}/${totalBatches}: deleting ${batch.length} files...`);

      if (!config.dryRun) {
        await Promise.all(batch.map(f => unlink(f)));
      }
    }

    logger.info('Cleanup complete');
  } finally {
    // flock is released automatically on process exit, but release explicitly
    // here so a long-running service can re-run cleanup without restarting.
    libc.symbols.flock(lockFd, LOCK_UN);
    closeSync(lockFd);
    logger.info('Lock released');
  }
}

