  destination: '/data/uploads/tmp/',
  filename: (req, file, cb) => {
    const chunkId = req.headers['x-chunk-id'] || crypto.randomUUID();
    cb(null, `chunk_${chunkId}_${Date.now()}.part`);
  },
});

const upload = multer({ storage, limits: { fileSize: MAX_FILE_SIZE } });

