import { uploadHandler } from '../middleware/upload-handler';
import { processUpload, cleanupTempFile } from '../services/upload-service';
import { logger } from '../logger';

const router = Router();

router.post('/upload', uploadHandler(), async (req, res) => {
  const tempPath = req.file?.path;
  if (!tempPath) return res.status(400).json({ error: 'No file provided' });

  const abortController = new AbortController();

  // Abort in-flight processing if the client disconnects
  req.on('close', () => {
    if (!res.writableEnded) {
      abortController.abort();
    }
  });

  try {
    const result = await processUpload(tempPath, {
      userId: req.user?.id,
      originalName: req.file!.originalname,
      mimeType: req.file!.mimetype,
      signal: abortController.signal,
    });
    res.json({ id: result.id, url: result.publicUrl });
  } catch (err) {
    if ((err as Error).name === 'AbortError') {
      logger.info('Upload cancelled by client, cleaning up:', tempPath);
      // Response is already closed — just fall through to cleanup
    } else {
      logger.error('Upload processing failed:', err);
      res.status(500).json({ error: 'Upload processing failed' });
    }
  } finally {
    await cleanupTempFile(tempPath, { signal: abortController.signal });
  }
});

export default router;

